import RealityKit

struct WeatherGlobeIntent: AppIntent {
    static var title: LocalizedStringResource = 'Weather Globe'
    @Parameter(title: 'Globe Type') var globeType: String
}

struct WeatherGlobeWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: 'WeatherGlobeWidget',
            intent: WeatherGlobeIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.globeType) {
                    content.add(model)
                }
            }
        }
    }
}

